import React, { useState, useRef } from "react";
import { api } from "../utils/api";

function CreateBook() {
  const [bookForm, setBookForm] = useState({
    authorName: "",
    bookName: "",
    genre: "",
    authorId: "",
  });
  const [photo, setPhoto] = useState(null);
  const [message, setMessage] = useState("");
  const fileInputRef = useRef();

  const handleChange = (e) => {
    setBookForm({ ...bookForm, [e.target.name]: e.target.value });
  };

  const handlePhoto = (e) => {
    setPhoto(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const formData = new FormData();
    Object.entries(bookForm).forEach(([key, value]) => {
      formData.append(key, value);
    });
    if (photo) {
      formData.append("photo", photo);
    }

    try {
      const res = await api.post(
        "/books/create-book",
        formData,
        {
          headers: { "Content-Type": "multipart/form-data" },
        }
      );

      console.log(res.data);
      setMessage("✅ Book created successfully!");
      setBookForm({ authorName: "", bookName: "", genre: "", authorId: "" });
      setPhoto(null);
      fileInputRef.current.value = "";
    } catch (err) {
      console.error("❌ Error creating book:", err.response || err.message);
      setMessage("❌ Something went wrong. Try again?");
    }
  };

  return (
    <div
      className="container my-5"
      style={{
        background: "linear-gradient(to bottom, #f9f5f0, #f4ede4)",
        padding: "40px",
        borderRadius: "15px",
        boxShadow: "0px 8px 20px rgba(0,0,0,0.15)",
        maxWidth: "700px",
      }}
    >
      <div className="text-center mb-4">
        <h2 style={{ fontFamily: "'Merriweather', serif", color: "#5a3825" }}>
          Upload your Book to our Shelf
        </h2>
        <p style={{ color: "#7b5e4a" }}>
          Fill in the details below and let the story begin.
        </p>
      </div>

      {message && (
        <div
          className={`alert ${
            message.startsWith("✅") ? "alert-success" : "alert-danger"
          }`}
        >
          {message}
        </div>
      )}

      <form onSubmit={handleSubmit} encType="multipart/form-data">
        {["authorName", "bookName", "genre", "authorId"].map((field) => (
          <div className="mb-3" key={field}>
            <label
              className="form-label fw-semibold"
              style={{ color: "#5a3825" }}
            >
              {field.replace(/([A-Z])/g, " $1")}
            </label>
            <input
              type="text"
              className="form-control shadow-sm"
              name={field}
              value={bookForm[field]}
              onChange={handleChange}
              style={{
                borderRadius: "8px",
                border: "1px solid #d4c2b0",
              }}
              required
            />
          </div>
        ))}

        <div className="mb-3">
          <label
            className="form-label fw-semibold"
            style={{ color: "#5a3825" }}
          >
            📷 Book Photo
          </label>
          <input
            ref={fileInputRef}
            type="file"
            className="form-control shadow-sm"
            accept="image/*"
            onChange={handlePhoto}
            style={{
              borderRadius: "8px",
              border: "1px solid #d4c2b0",
            }}
          />
        </div>

        <button
          type="submit"
          className="btn w-100"
          style={{
            backgroundColor: "#8B4513",
            color: "white",
            fontWeight: "bold",
            borderRadius: "8px",
            padding: "10px 0",
            transition: "0.3s",
          }}
          onMouseOver={(e) => (e.target.style.backgroundColor = "#5a2f0c")}
          onMouseOut={(e) => (e.target.style.backgroundColor = "#8B4513")}
        >
          Add Book
        </button>
      </form>
    </div>
  );
}

export default CreateBook;
