import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { api, getUploadUrl } from "../utils/api";

function BuyPage() {
  const { bookId } = useParams();
  const navigate = useNavigate();
  const [book, setBook] = useState(null);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState("");

  // ✅ Fetch book details
  useEffect(() => {
    api
      .get(`/books/get-book/${bookId}`)
      .then((res) => {
        if (res.data?.data) {
          setBook(res.data.data);
        } else {
          setErrorMsg("📚 Book not found.");
        }
      })
      .catch(() => {
        setErrorMsg("❌ Failed to load book details.");
      })
      .finally(() => {
        setLoading(false);
      });
  }, [bookId]);

  // ✅ Payment
  const handlePayment = () => {
    navigate("/checkout", { state: { book } });
  };

  if (loading)
    return (
      <p className="text-center mt-4 fs-4 text-primary">⏳ Loading book details...</p>
    );

  if (errorMsg)
    return <p className="text-danger text-center mt-4 fs-5">{errorMsg}</p>;

  return (
    <div className="container py-5" style={{ maxWidth: "800px" }}>
      <div className="card shadow-lg border-0 rounded-4 p-4">
        {/* Book Image */}
        {book?.bookPhoto && (
          <div className="text-center">
            <img
              src={getUploadUrl(book.bookPhoto)}
              alt="Book"
              className="rounded-4 shadow"
              style={{
                width: "220px",
                height: "300px",
                objectFit: "cover",
                border: "4px solid #f0f0f0",
              }}
            />
          </div>
        )}

        {/* Book Info */}
        <div className="mt-4 text-center">
          <h2 className="fw-bold text-primary">{book?.bookName}</h2>
          <p className="mb-1">
            <strong> Author:</strong> {book?.authorName}
          </p>
          <p className="mb-1">
            <strong> Genre:</strong> {book?.genre}
          </p>
          <p className="mb-4">
            <strong> Author ID:</strong> {book?.authorId}
          </p>
        </div>

        {/* Buttons */}
        <div className="d-flex justify-content-center gap-3 mt-3">
          <button
            className="btn btn-success px-4 py-2 rounded-pill fw-bold"
            onClick={handlePayment}
          >
            💳 Proceed to Payment
          </button>
          <button
            className="btn btn-outline-secondary px-4 py-2 rounded-pill"
            onClick={() => navigate(-1)}
          >
            🔙 Back
          </button>
        </div>
      </div>
    </div>
  );
}

export default BuyPage;
