import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { api, getUploadUrl } from "../utils/api";

function BookList() {
  const [books, setBooks] = useState([]);
  const [errorMsg, setErrorMsg] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchBooks = () => {
    api
      .get("/books/get-books")
      .then((res) => {
        if (res.data?.data) {
          setBooks(res.data.data);
        } else {
          setErrorMsg("No data received from server.");
        }
      })
      .catch((err) => {
        const status = err.response?.status || "unknown";
        const message = err.response?.data?.message || "Something went wrong";
        setErrorMsg(`Server error: ${status} - ${message}`);
      });
  };

  useEffect(() => {
    fetchBooks();
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this book?")) return;

    try {
      setLoading(true);
      await api.delete(`/books/delete-book/${id}`);
      setBooks((prev) => prev.filter((book) => book._id !== id));
    } catch (err) {
      console.error("❌ Error deleting book:", err.message);
      alert("Failed to delete book");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className="container mt-4"
      style={{
        backgroundColor: "#f8f4e3", // Warm bookstore beige
        padding: "30px",
        borderRadius: "15px",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
      }}
    >
      <h2
        style={{
          fontFamily: "'Merriweather', serif",
          fontWeight: "bold",
          color: "#5d4037",
          borderBottom: "3px solid #d7ccc8",
          paddingBottom: "10px",
          marginBottom: "20px",
        }}
      >
        Browse Our Collection
      </h2>

      {errorMsg && <p className="text-danger">{errorMsg}</p>}
      {loading && <p>Processing...</p>}

      <div className="row">
        {books?.length > 0
          ? books.map((book, index) => (
              <div className="col-md-4" key={index}>
                <div
                  className="card mb-4"
                  style={{
                    border: "none",
                    borderRadius: "12px",
                    overflow: "hidden",
                    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
                    transition: "transform 0.2s",
                  }}
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.transform = "scale(1.03)")
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.transform = "scale(1)")
                  }
                >
                  {book.bookPhoto && (
                    <img
                      src={getUploadUrl(book.bookPhoto)}
                      alt="Book"
                      style={{
                        height: "250px",
                        objectFit: "cover",
                        width: "100%",
                      }}
                    />
                  )}
                  <div
                    className="card-body"
                    style={{ backgroundColor: "#fff8e1", minHeight: "200px" }}
                  >
                    <h5
                      className="card-title"
                      style={{
                        fontFamily: "'Playfair Display', serif",
                        fontWeight: "bold",
                        color: "#4e342e",
                      }}
                    >
                      {book.bookName}
                    </h5>
                    <p
                      className="card-text"
                      style={{ color: "#6d4c41", fontSize: "14px" }}
                    >
                      <strong>Author:</strong> {book.authorName} <br />
                      <strong>Genre:</strong> {book.genre} <br />
                      <strong>Author ID:</strong> {book.authorId}
                    </p>

                    <div className="d-flex justify-content-between">
                      <Link
                        to={`/buy/${book._id}`}
                        className="btn btn-sm"
                        style={{
                          backgroundColor: "#8d6e63",
                          color: "#fff",
                          borderRadius: "8px",
                          padding: "6px 12px",
                        }}
                      >
                        🛒 Buy
                      </Link>
                      <button
                        className="btn btn-sm"
                        style={{
                          backgroundColor: "#d84315",
                          color: "#fff",
                          borderRadius: "8px",
                          padding: "6px 12px",
                        }}
                        onClick={() => handleDelete(book._id)}
                        disabled={loading}
                      >
                        🗑️ Delete
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))
          : !errorMsg && <p>No books found.</p>}
      </div>
    </div>
  );
}

export default BookList;
