import React, { useState } from "react";
import avatarImage from "../assets/siddiq.jpg"; // Adjust path if needed
import "./Profile.css";

const Profile = () => {
  const initialUser = {
    fullName: "Abubacker Siddiq",
    username: "siddiq",
    email: "jabubackersiddiq",
    phone: "+916381871801",
    address: "31/16 Mariya Doss Street Royapuram Chennai 600013",
    bio: "A passionate book lover and tech enthusiast who enjoys building digital libraries.",
    avatar: avatarImage,
  };

  const [user, setUser] = useState(initialUser);
  const [editMode, setEditMode] = useState(false);
  const [form, setForm] = useState(initialUser);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const toggleEdit = () => {
    if (editMode) {
      setUser(form);
    }
    setEditMode(!editMode);
  };

  return (
    <div
      className="profile-container bg-light p-4 rounded shadow-sm"
      style={{ fontFamily: "'Merriweather', serif" }}
    >
      {/* Profile Header */}
      <div className="profile-header d-flex align-items-center mb-4">
        <img
          src={user.avatar}
          alt="User Avatar"
          className="profile-avatar rounded-circle border border-3 border-warning"
          style={{ width: "120px", height: "120px", objectFit: "cover" }}
        />
        <div className="profile-info ms-4">
          {editMode ? (
            <>
              <input
                type="text"
                name="fullName"
                value={form.fullName}
                onChange={handleChange}
                className="form-control mb-2"
                placeholder="Full Name"
              />
              <input
                type="text"
                name="username"
                value={form.username}
                onChange={handleChange}
                className="form-control"
                placeholder="Username"
              />
            </>
          ) : (
            <>
              <h2 className="fw-bold text-brown">{user.fullName}</h2>
              <p className="text-muted">@{user.username}</p>
            </>
          )}
        </div>
      </div>

      {/* Profile Details */}
      <div className="profile-details">
        <label className="fw-bold mt-2"> Email</label>
        <span className="d-block mb-2">{user.email}</span>

        <label className="fw-bold"> Phone</label>
        {editMode ? (
          <input
            type="tel"
            name="phone"
            value={form.phone}
            onChange={handleChange}
            className="form-control mb-2"
          />
        ) : (
          <span className="d-block mb-2">{user.phone}</span>
        )}

        <label className="fw-bold"> Address</label>
        {editMode ? (
          <textarea
            name="address"
            value={form.address}
            onChange={handleChange}
            className="form-control mb-2"
            rows="2"
          />
        ) : (
          <span className="d-block mb-2">{user.address}</span>
        )}

        <label className="fw-bold"> Bio</label>
        {editMode ? (
          <textarea
            name="bio"
            value={form.bio}
            onChange={handleChange}
            className="form-control"
            rows="3"
          />
        ) : (
          <span className="d-block">{user.bio}</span>
        )}
      </div>

      {/* Action Button */}
      <button
        className="btn btn-warning mt-4 w-100 fw-bold"
        onClick={toggleEdit}
      >
        {editMode ? " Save Profile" : " Edit Profile"}
      </button>
    </div>
  );
};

export default Profile;
