import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";

function PreOrder() {
  const location = useLocation();
  const navigate = useNavigate();

  const book = location.state?.book || {
    title: "Unknown Book",
    author: "Unknown Author",
    img: "",
    price: "₹19.99",
    rating: 4.5,
  };
  const [preOrdered, setPreOrdered] = useState(false);

  const handlePreOrder = () => {
    setPreOrdered(true);
    setTimeout(() => {
      navigate("/home");
    }, 2000);
  };

  // Function to render rating stars
  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const halfStar = rating % 1 >= 0.5;
    for (let i = 0; i < fullStars; i++) stars.push("★");
    if (halfStar) stars.push("☆");
    return stars.join(" ");
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "linear-gradient(135deg, #fdf6e3, #f8e1c4)",
        padding: "20px",
        fontFamily: "'Merriweather', serif",
      }}
    >
      <div
        style={{
          maxWidth: "420px",
          width: "100%",
          backgroundColor: "#fffaf5",
          borderRadius: "15px",
          boxShadow: "0 15px 40px rgba(0,0,0,0.15)",
          overflow: "hidden",
          animation: "fadeIn 0.6s ease-in-out",
        }}
      >
        {/* Book Cover */}
        {book.img && (
          <img
            src={book.img}
            alt={book.title}
            style={{
              width: "100%",
              height: "350px",
              objectFit: "cover",
              borderBottom: "3px solid #d4a373",
            }}
          />
        )}

        {/* Book Info */}
        <div style={{ padding: "20px", textAlign: "center" }}>
          <h2
            style={{ margin: "10px 0", fontSize: "1.8rem", color: "#5a3e2b" }}
          >
            {book.title}
          </h2>
          <p style={{ margin: "5px 0", fontSize: "1.1rem", color: "#7b5e46" }}>
            by <strong>{book.author}</strong>
          </p>
          <p
            style={{
              margin: "8px 0",
              fontSize: "1.1rem",
              color: "#ff9800",
              letterSpacing: "2px",
            }}
          >
            {renderStars(book.rating)}
          </p>
          <p
            style={{
              margin: "12px 0",
              fontSize: "1.3rem",
              fontWeight: "bold",
              color: "#4b2e20",
            }}
          >
            {book.price}
          </p>

          {!preOrdered ? (
            <button
              onClick={handlePreOrder}
              style={{
                padding: "12px 24px",
                fontSize: "1rem",
                borderRadius: "8px",
                border: "none",
                backgroundColor: "#d4a373",
                color: "#fff",
                cursor: "pointer",
                width: "100%",
                transition: "all 0.3s ease",
                fontWeight: "bold",
              }}
              onMouseEnter={(e) =>
                (e.currentTarget.style.backgroundColor = "#b07a50")
              }
              onMouseLeave={(e) =>
                (e.currentTarget.style.backgroundColor = "#d4a373")
              }
            >
              Pre-order Now
            </button>
          ) : (
            <div
              style={{
                marginTop: "20px",
                padding: "15px",
                backgroundColor: "#e8f5e9",
                borderRadius: "8px",
                color: "#2e7d32",
                fontWeight: "600",
                fontSize: "1rem",
                animation: "fadeIn 0.5s ease-in-out",
              }}
            >
              ✅ Pre-ordered Successfully! Returning to home...
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default PreOrder;
