import React, { useState } from "react";
import { Link } from "react-router-dom";
import books from "../data/books"; // Import your book data

function BrowseBooks() {
  const [sortKey, setSortKey] = useState("title");

  // Sorting logic
  const sortedBooks = [...books].sort((a, b) => {
    if (sortKey === "title" || sortKey === "author") {
      return a[sortKey].localeCompare(b[sortKey]);
    } else if (sortKey === "rating" || sortKey === "price") {
      return b[sortKey] - a[sortKey];
    }
    return 0;
  });

  const renderStars = (rating) => {
    const fullStars = Math.floor(rating);
    const halfStar = rating % 1 >= 0.5;
    const stars = [];

    for (let i = 0; i < fullStars; i++) {
      stars.push(
        <span key={"full" + i} style={{ color: "#f5c518" }}>
          ★
        </span>
      );
    }
    if (halfStar) {
      stars.push(
        <span key="half" style={{ color: "#f5c518" }}>
          ☆
        </span>
      );
    }
    while (stars.length < 5) {
      stars.push(
        <span key={"empty" + stars.length} style={{ color: "#ddd" }}>
          ★
        </span>
      );
    }
    return stars;
  };

  return (
    <div
      className="py-4"
      style={{
        backgroundColor: "#f8f4ec", // Warm beige background
        minHeight: "100vh",
      }}
    >
      <div className="container">
        <h2 className="mb-4 text-center fw-bold" style={{ color: "#5a3825" }}>
           Browse Our Collection
        </h2>

        {/* Sorting Options */}
        <div className="mb-4 text-center">
          <label
            htmlFor="sort"
            className="me-2 fw-semibold"
            style={{ color: "#5a3825" }}
          >
            Sort By:
          </label>
          <select
            id="sort"
            className="form-select d-inline-block w-auto shadow-sm border-0"
            value={sortKey}
            onChange={(e) => setSortKey(e.target.value)}
            style={{
              backgroundColor: "#fff",
              color: "#5a3825",
              borderRadius: "8px",
            }}
          >
            <option value="title">Title (A-Z)</option>
            <option value="author">Author (A-Z)</option>
            <option value="rating">Rating (High to Low)</option>
            <option value="price">Price (High to Low)</option>
          </select>
        </div>

        {/* Books Grid */}
        <div className="row g-4">
          {sortedBooks.map((book) => (
            <div className="col-sm-6 col-md-4 col-lg-3" key={book.id}>
              <div
                className="card h-100 shadow-sm border-0"
                style={{
                  borderRadius: "15px",
                  transition: "transform 0.2s ease, box-shadow 0.2s ease",
                  backgroundColor: "#fff",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = "translateY(-5px)";
                  e.currentTarget.style.boxShadow =
                    "0 8px 20px rgba(0,0,0,0.15)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = "translateY(0)";
                  e.currentTarget.style.boxShadow =
                    "0 4px 10px rgba(0,0,0,0.05)";
                }}
              >
                <img
                  src={book.img}
                  className="card-img-top"
                  alt={book.title}
                  style={{
                    height: "250px",
                    objectFit: "cover",
                    borderTopLeftRadius: "15px",
                    borderTopRightRadius: "15px",
                  }}
                />
                <div className="card-body d-flex flex-column">
                  <h5
                    className="card-title fw-bold"
                    style={{ color: "#5a3825" }}
                  >
                    <Link
                      to={`/books/${book.id}`}
                      style={{
                        textDecoration: "none",
                        color: "#5a3825",
                      }}
                    >
                      {book.title}
                    </Link>
                  </h5>
                  <p className="card-text text-muted mb-1">by {book.author}</p>
                  <div className="mb-2">{renderStars(book.rating)}</div>
                  <p className="fw-bold mb-2" style={{ color: "#8b0000" }}>
                    ₹{book.price}
                  </p>
                  <Link
                    to={`/books/${book.id}`}
                    className="btn btn-outline-dark mt-auto"
                    style={{ borderRadius: "8px" }}
                  >
                    View Details
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default BrowseBooks;
