import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { FiBook, FiList } from "react-icons/fi";
import siddiq from "../assets/siddiq.jpg";

function MenuBar() {
  const navigate = useNavigate();
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) setUser(storedUser);
  }, []);

  const displayName =
    user?.username ||
    user?.name ||
    user?.email?.split("@")[0] ||
    "Account";

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <nav
      className="navbar navbar-expand-lg"
      style={{
        backdropFilter: "blur(8px)",
        background: "rgba(245, 235, 220, 0.95)", // warm parchment tone
        padding: "0.8rem 2rem",
        boxShadow: "0 6px 20px rgba(0,0,0,0.2)",
        position: "sticky",
        top: 0,
        zIndex: 1000,
        borderBottom: "1px solid rgba(150,100,50,0.3)",
      }}
    >
      <div className="container-fluid">
        {/* Logo */}
        <Link to="/" className="navbar-brand d-flex align-items-center">
          <img
            src="https://cdn-icons-png.flaticon.com/512/29/29302.png"
            alt="Booksouls Logo"
            style={{
              height: "40px",
              marginRight: "12px",
              filter: "drop-shadow(1px 1px 2px #8B5E3C)",
              transition: "all 0.3s",
            }}
          />
          <span
            style={{
              fontFamily: "'Merriweather', serif",
              fontSize: "1.6rem",
              fontWeight: "700",
              color: "#6B4C3B", // dark brown
              letterSpacing: "1px",
            }}
          >
            Booksouls
          </span>
        </Link>

        {/* Toggler */}
        <button
          className="navbar-toggler"
          type="button"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{
            border: "1px solid #6B4C3B",
            background: "rgba(200,180,150,0.2)",
            padding: "8px",
            borderRadius: "8px",
            transition: "all 0.3s",
          }}
        >
          <span
            className="navbar-toggler-icon"
            style={{ filter: "invert(0.3)" }}
          ></span>
        </button>

        <div className={`collapse navbar-collapse ${menuOpen ? "show" : ""}`}>
          <ul className="navbar-nav ms-auto mb-2 mb-lg-0 align-items-center">
            {/* Icon Links */}
            {[
              {
                to: "/create-employee",
                icon: <FiBook size={24} />,
                title: "Create Book",
              },
              {
                to: "/employee-list",
                icon: <FiList size={24} />,
                title: "Book List",
              },
            ].map((item, idx) => (
              <li className="nav-item mx-2" key={idx}>
                <Link
                  to={item.to}
                  className="nav-link d-flex align-items-center justify-content-center"
                  title={item.title}
                  style={{
                    width: "46px",
                    height: "46px",
                    borderRadius: "12px",
                    background: "rgba(210,180,140,0.2)", // subtle beige
                    boxShadow: "0 3px 6px rgba(150,100,50,0.3)",
                    transition: "all 0.3s",
                    color: "#6B4C3B",
                  }}
                >
                  {item.icon}
                </Link>
              </li>
            ))}

            {/* Profile Dropdown */}
            <li className="nav-item dropdown ms-3 position-relative">
              <button
                className="btn d-flex align-items-center"
                style={{
                  background: "rgba(210,180,140,0.3)", // beige
                  border: "1px solid rgba(150,100,50,0.6)",
                  padding: "10px 20px",
                  borderRadius: "30px",
                  fontWeight: "600",
                  color: "#4B2E2E", // darker brown
                  boxShadow: "0 3px 12px rgba(150,100,50,0.2)",
                  transition: "all 0.3s",
                  gap: "10px",
                  fontSize: "1rem",
                  cursor: "pointer",
                  backdropFilter: "blur(4px)",
                }}
                onClick={() => setDropdownOpen(!dropdownOpen)}
              >
                <img
                  src={siddiq}
                  alt="Account Logo"
                  style={{
                    width: "38px",
                    height: "38px",
                    borderRadius: "50%",
                    objectFit: "cover",
                    border: "2px solid #8B5E3C",
                  }}
                />
                <span>{displayName}</span>
              </button>

              {dropdownOpen && (
                <ul
                  className="dropdown-menu dropdown-menu-end show"
                  style={{
                    background: "rgba(240,230,210,0.95)", // light parchment
                    borderRadius: "16px",
                    boxShadow: "0 10px 25px rgba(150,100,50,0.3)",
                    marginTop: "12px",
                    minWidth: "220px",
                    padding: "8px 0",
                    animation: "slideFade 0.25s ease forwards",
                    color: "#4B2E2E",
                  }}
                >
                  {["Profile", "Settings"].map((label, idx) => (
                    <li key={idx}>
                      <Link
                        className="dropdown-item"
                        to={`/${label.toLowerCase()}`}
                        onClick={() => setDropdownOpen(false)}
                        style={{
                          fontWeight: "500",
                          padding: "12px 20px",
                          borderRadius: "8px",
                          transition: "all 0.2s",
                          color: "#4B2E2E",
                        }}
                      >
                        {label}
                      </Link>
                    </li>
                  ))}
                  <li>
                    <hr
                      style={{
                        margin: "8px 0",
                        borderColor: "rgba(150,100,50,0.2)",
                      }}
                    />
                  </li>
                  <li>
                    <button
                      className="dropdown-item"
                      onClick={() => {
                        setDropdownOpen(false);
                        handleLogout();
                      }}
                      style={{
                        fontWeight: "500",
                        padding: "12px 20px",
                        borderRadius: "8px",
                        background: "transparent",
                        border: "none",
                        width: "100%",
                        textAlign: "left",
                        cursor: "pointer",
                        transition: "all 0.2s",
                        color: "#B22222", // red-brown logout
                      }}
                    >
                      Logout
                    </button>
                  </li>
                </ul>
              )}
            </li>
          </ul>
        </div>
      </div>

      <style>
        {`
          @keyframes slideFade {
            0% {opacity: 0; transform: translateY(-10px);}
            100% {opacity: 1; transform: translateY(0);}
          }
        `}
      </style>
    </nav>
  );
}

export default MenuBar;
